import { useEffect, useState } from "react";
import type { ReactNode } from "react";
import {
  BrowserRouter,
  Link,
  Navigate,
  NavLink,
  Route,
  Routes,
  useNavigate,
  useLocation,
} from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import type { RootState, AppDispatch } from "./store/store";

import { loadMe } from "./features/auth/authSlice";
import { logout } from "./features/auth/authSlice";
import CreateParcelPage from "./pages/CreateParcelPage";
import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import OrderHistoryPage from "./pages/OrderHistoryPage";
import TrackParcelPage from "./pages/TrackParcelPage";
import AiAssistantPage from "./pages/AiAssistantPage";
import HomePage from "./pages/HomePage";
import ForgotPasswordPage from "./pages/ForgotPasswordPage";
import ResetPasswordPage from "./pages/ResetPasswordPage";

function RequireAuth({ children }: { children: ReactNode }) {
  const token = useSelector((s: RootState) => s.auth.token);
  if (!token) return <Navigate to="/login" replace />;
  return <>{children}</>;
}

function Navbar({ mobileOpen, setMobileOpen }: { mobileOpen: boolean; setMobileOpen: (v: boolean) => void }) {
  const token = useSelector((s: RootState) => s.auth.token);
  const user = useSelector((s: RootState) => s.auth.user);
  const dispatch = useDispatch<AppDispatch>();
  const navigate = useNavigate();
  const location = useLocation();

  const isHome = location.pathname === "/";

  function onLogout() {
    dispatch(logout());
    navigate("/");
    setMobileOpen(false);
  }

  return (
    <header className="navbar">
      <div className="navbar-inner">
        {/* Logo */}
        <Link to="/" className="navbar-logo" onClick={() => setMobileOpen(false)}>
          <span className="navbar-logo-dot" />
          Courier Nepal
        </Link>

        {/* Desktop Nav */}
        <nav className="navbar-nav">
          {!isHome && (
            <>
              <NavLink to="/track" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>Track</NavLink>
              <NavLink to="/create" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>Schedule Pickup</NavLink>
              <NavLink to="/history" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>Order History</NavLink>
              <NavLink to="/ai" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>AI Assistant</NavLink>
            </>
          )}
        </nav>

        {/* Actions */}
        <div className="navbar-actions">
          {token ? (
            <>
              <span className="navbar-user" style={{ display: "none" } as any}>
                {user?.name ? `Hi, ${user.name}` : "Signed in"}
              </span>
              <span className="navbar-user">{user?.name ? `Hi, ${user.name}` : "Signed in"}</span>
              <button onClick={onLogout} className="btn-nav-outline">Logout</button>
            </>
          ) : (
            <>
              <Link to="/login" className="btn-nav-outline">Login</Link>
              <Link to="/register" className="btn-nav-primary">Register</Link>
            </>
          )}
          {/* Mobile toggle */}
          <button className="navbar-toggle" onClick={() => setMobileOpen(!mobileOpen)} aria-label="Toggle menu">
            {mobileOpen ? "Γ£ò" : "Γÿ░"}
          </button>
        </div>
      </div>

      {/* Mobile drawer */}
      {mobileOpen && (
        <div style={{
          background: "var(--bg-darker)",
          borderTop: "1px solid var(--border)",
          padding: "12px 16px",
          display: "flex",
          flexDirection: "column",
          gap: "4px",
        }}>
          <NavLink to="/" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`} onClick={() => setMobileOpen(false)}>Home</NavLink>
          <NavLink to="/track" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`} onClick={() => setMobileOpen(false)}>Track</NavLink>
          <NavLink to="/create" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`} onClick={() => setMobileOpen(false)}>Schedule Pickup</NavLink>
          <NavLink to="/history" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`} onClick={() => setMobileOpen(false)}>Order History</NavLink>
          <NavLink to="/ai" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`} onClick={() => setMobileOpen(false)}>AI Assistant</NavLink>
          {token ? (
            <button onClick={onLogout} className="btn-secondary" style={{ marginTop: "8px" }}>Logout</button>
          ) : (
            <div style={{ display: "flex", gap: "8px", marginTop: "8px" }}>
              <Link to="/login" className="btn-secondary" style={{ flex: 1, textAlign: "center" }} onClick={() => setMobileOpen(false)}>Login</Link>
              <Link to="/register" className="btn-primary" style={{ flex: 1, textAlign: "center" }} onClick={() => setMobileOpen(false)}>Register</Link>
            </div>
          )}
        </div>
      )}
    </header>
  );
}

function AppInner() {
  const dispatch = useDispatch<AppDispatch>();
  const token = useSelector((s: RootState) => s.auth.token);
  const user = useSelector((s: RootState) => s.auth.user);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    if (token && !user) {
      dispatch(loadMe());
    }
  }, [dispatch, token, user]);

  return (
    <div className="app-shell">
      <Navbar mobileOpen={mobileOpen} setMobileOpen={setMobileOpen} />

      <main className="page-main">
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/forgot-password" element={<ForgotPasswordPage />} />
          <Route path="/reset-password" element={<ResetPasswordPage />} />
          <Route
            path="/track"
            element={
              <RequireAuth>
                <TrackParcelPage />
              </RequireAuth>
            }
          />
          <Route
            path="/create"
            element={
              <RequireAuth>
                <CreateParcelPage />
              </RequireAuth>
            }
          />
          <Route
            path="/history"
            element={
              <RequireAuth>
                <OrderHistoryPage />
              </RequireAuth>
            }
          />
          <Route path="/ai" element={<AiAssistantPage />} />
        </Routes>
      </main>

      <footer className="footer">
        ┬⌐ {new Date().getFullYear()} Courier Nepal ┬╖ Built for Nepal's courier needs
      </footer>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <AppInner />
    </BrowserRouter>
  );
}

import { createAsyncThunk, createSlice } from "@reduxjs/toolkit";
import type { PayloadAction } from "@reduxjs/toolkit";
import { http, setAuthToken } from "../../api/http";

export type AppRole = "USER" | "ADMIN" | "SUPER_ADMIN" | "DELIVERY_STAFF";

export type User = {
  id: number;
  name: string;
  email: string;
  phone?: string | null;
  role: AppRole;
};

type AuthState = {
  token: string | null;
  user: User | null;
  status: "idle" | "loading" | "succeeded" | "failed";
  error: string | null;
};

const storedToken = localStorage.getItem("token");
if (storedToken) setAuthToken(storedToken);

const initialState: AuthState = {
  token: storedToken,
  user: null,
  status: "idle",
  error: null,
};

// ΓöÇΓöÇ Thunks ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export const login = createAsyncThunk(
  "auth/login",
  async (payload: { email: string; password: string }, { rejectWithValue }) => {
    try {
      const res = await http.post("/api/auth/login", payload);
      return res.data as { token: string; user: User };
    } catch (err: any) {
      return rejectWithValue(err?.response?.data?.message || "Login failed");
    }
  }
);

export const register = createAsyncThunk(
  "auth/register",
  async (
    payload: { name: string; email: string; phone?: string; password: string },
    { rejectWithValue }
  ) => {
    try {
      const res = await http.post("/api/auth/register", payload);
      return res.data as { token: string; user: User };
    } catch (err: any) {
      return rejectWithValue(
        err?.response?.data?.message || "Registration failed"
      );
    }
  }
);

export const loadMe = createAsyncThunk(
  "auth/me",
  async (_, { rejectWithValue, getState }) => {
    try {
      const state = getState() as { auth: AuthState };
      if (!state.auth.token) return rejectWithValue("Not authenticated");
      const res = await http.get("/api/auth/me");
      return res.data as { user: User };
    } catch (err: any) {
      return rejectWithValue(err?.response?.data?.message || "Failed to load user");
    }
  }
);

export const forgotPassword = createAsyncThunk(
  "auth/forgotPassword",
  async (payload: { email: string }, { rejectWithValue }) => {
    try {
      const res = await http.post("/api/auth/forgot-password", payload);
      return res.data as { message: string };
    } catch (err: any) {
      return rejectWithValue(
        err?.response?.data?.message || "Failed to send reset email"
      );
    }
  }
);

export const resetPassword = createAsyncThunk(
  "auth/resetPassword",
  async (payload: { token: string; password: string }, { rejectWithValue }) => {
    try {
      const res = await http.post("/api/auth/reset-password", payload);
      return res.data as { message: string };
    } catch (err: any) {
      return rejectWithValue(
        err?.response?.data?.message || "Failed to reset password"
      );
    }
  }
);

// ΓöÇΓöÇ Slice ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const authSlice = createSlice({
  name: "auth",
  initialState,
  reducers: {
    logout(state) {
      state.token = null;
      state.user = null;
      state.status = "idle";
      state.error = null;
      localStorage.removeItem("token");
      setAuthToken(null);
    },
    setToken(state, action: PayloadAction<string | null>) {
      state.token = action.payload;
      if (action.payload) {
        localStorage.setItem("token", action.payload);
        setAuthToken(action.payload);
      } else {
        localStorage.removeItem("token");
        setAuthToken(null);
      }
    },
  },
  extraReducers: (builder) => {
    builder
      // login
      .addCase(login.pending, (state) => { state.status = "loading"; state.error = null; })
      .addCase(login.fulfilled, (state, action) => {
        state.status = "succeeded";
        state.token = action.payload.token;
        state.user = action.payload.user;
        state.error = null;
        localStorage.setItem("token", action.payload.token);
        setAuthToken(action.payload.token);
      })
      .addCase(login.rejected, (state, action) => {
        state.status = "failed";
        state.error = (action.payload as string) || "Login failed";
      })
      // register
      .addCase(register.pending, (state) => { state.status = "loading"; state.error = null; })
      .addCase(register.fulfilled, (state, action) => {
        state.status = "succeeded";
        state.token = action.payload.token;
        state.user = action.payload.user;
        state.error = null;
        localStorage.setItem("token", action.payload.token);
        setAuthToken(action.payload.token);
      })
      .addCase(register.rejected, (state, action) => {
        state.status = "failed";
        state.error = (action.payload as string) || "Registration failed";
      })
      // loadMe
      .addCase(loadMe.fulfilled, (state, action) => { state.user = action.payload.user; })
      // forgotPassword / resetPassword ΓÇö status only, no token changes
      .addCase(forgotPassword.pending, (state) => { state.status = "loading"; state.error = null; })
      .addCase(forgotPassword.fulfilled, (state) => { state.status = "succeeded"; })
      .addCase(forgotPassword.rejected, (state, action) => {
        state.status = "failed";
        state.error = (action.payload as string) || "Failed";
      })
      .addCase(resetPassword.pending, (state) => { state.status = "loading"; state.error = null; })
      .addCase(resetPassword.fulfilled, (state) => { state.status = "succeeded"; })
      .addCase(resetPassword.rejected, (state, action) => {
        state.status = "failed";
        state.error = (action.payload as string) || "Failed";
      });
  },
});

export const { logout, setToken } = authSlice.actions;

export default authSlice.reducer;

import { createAsyncThunk, createSlice } from "@reduxjs/toolkit";
import { http } from "../../api/http";

export type ParcelEvent = {
  id: number;
  status: "PICKED" | "IN_TRANSIT" | "OUT_FOR_DELIVERY" | "DELIVERED";
  updatedByUserId: number | null;
  createdAt: string;
};

export type ParcelTrack = {
  parcelId: number;
  status: ParcelEvent["status"];
  events: ParcelEvent[];
};

export type Payment = {
  id: number;
  provider: "ESEWA" | "KHALTI";
  amount: string;
  status: "PENDING" | "SUCCESS" | "FAILED";
  providerTransactionId?: string | null;
  receiptCode?: string | null;
  createdAt: string;
};

export type ParcelHistoryItem = {
  id: number;
  status: ParcelTrack["status"];
  pickupScheduledAt?: string | null;
  receiverName: string;
  receiverPhone: string;
  receiverAddressLine1: string;
  receiverCity?: string | null;
  createdAt: string;
  events: ParcelEvent[];
  payments: Payment[];
};

type ParcelsState = {
  tracking: ParcelTrack | null;
  history: ParcelHistoryItem[] | null;
  status: "idle" | "loading" | "succeeded" | "failed";
  historyStatus: "idle" | "loading" | "succeeded" | "failed";
  createStatus: "idle" | "loading" | "succeeded" | "failed";
  error: string | null;
  createError: string | null;
  historyError: string | null;
};

const initialState: ParcelsState = {
  tracking: null,
  history: null,
  status: "idle",
  historyStatus: "idle",
  createStatus: "idle",
  error: null,
  createError: null,
  historyError: null,
};

export const trackParcel = createAsyncThunk(
  "parcels/track",
  async (parcelId: number, { rejectWithValue }) => {
    try {
      const res = await http.get(`/api/parcels/${parcelId}/track`);
      return res.data as ParcelTrack;
    } catch (err: any) {
      return rejectWithValue(err?.response?.data?.message || "Tracking failed");
    }
  }
);

export const createParcel = createAsyncThunk(
  "parcels/create",
  async (
    payload: {
      pickupScheduledAt?: string | null;
      pickupAddressLine1: string;
      pickupAddressLine2?: string | null;
      pickupCity?: string | null;
      receiverName: string;
      receiverPhone: string;
      receiverAddressLine1: string;
      receiverAddressLine2?: string | null;
      receiverCity?: string | null;
      parcelType?: string | null;
      weightKg?: number | null;
      notes?: string | null;
    },
    { rejectWithValue }
  ) => {
    try {
      const res = await http.post("/api/parcels", payload);
      return res.data as { parcelId: number };
    } catch (err: any) {
      return rejectWithValue(err?.response?.data?.message || "Create parcel failed");
    }
  }
);

export const fetchOrderHistory = createAsyncThunk(
  "parcels/history",
  async (_, { rejectWithValue }) => {
    try {
      const res = await http.get("/api/parcels/history");
      return res.data as { parcels: ParcelHistoryItem[] };
    } catch (err: any) {
      return rejectWithValue(err?.response?.data?.message || "Failed to load order history");
    }
  }
);

const parcelsSlice = createSlice({
  name: "parcels",
  initialState,
  reducers: {
    clearTracking(state) {
      state.tracking = null;
      state.status = "idle";
      state.error = null;
    },
    clearHistory(state) {
      state.history = null;
      state.historyStatus = "idle";
      state.historyError = null;
    },
  },
  extraReducers: (builder) => {
    builder
      .addCase(trackParcel.pending, (state) => {
        state.status = "loading";
        state.error = null;
      })
      .addCase(trackParcel.fulfilled, (state, action) => {
        state.status = "succeeded";
        state.tracking = action.payload;
      })
      .addCase(trackParcel.rejected, (state, action) => {
        state.status = "failed";
        state.error = (action.payload as string) || "Tracking failed";
      })
      .addCase(createParcel.pending, (state) => {
        state.createStatus = "loading";
        state.createError = null;
      })
      .addCase(createParcel.fulfilled, (state) => {
        state.createStatus = "succeeded";
      })
      .addCase(createParcel.rejected, (state, action) => {
        state.createStatus = "failed";
        state.createError = (action.payload as string) || "Create parcel failed";
      })
      .addCase(fetchOrderHistory.pending, (state) => {
        state.historyStatus = "loading";
        state.historyError = null;
      })
      .addCase(fetchOrderHistory.fulfilled, (state, action) => {
        state.historyStatus = "succeeded";
        state.history = action.payload.parcels;
      })
      .addCase(fetchOrderHistory.rejected, (state, action) => {
        state.historyStatus = "failed";
        state.historyError = (action.payload as string) || "Failed to load order history";
      });
  },
});

export const { clearTracking, clearHistory } = parcelsSlice.actions;
export default parcelsSlice.reducer;

import { useState, useRef, useEffect } from "react";
import type { FormEvent } from "react";
import { http } from "../api/http";

type ChatItem = { id: string; from: "user" | "assistant"; text: string };

export default function AiAssistantPage() {
  const [question, setQuestion] = useState("");
  const [items, setItems] = useState<ChatItem[]>([
    {
      id: "welcome",
      from: "assistant",
      text: "Hi! ≡ƒæï I'm your Courier Nepal assistant. Ask me about parcel tracking, pickup scheduling, or payments (eSewa / Khalti).",
    },
  ]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [items, loading]);

  async function onAsk(e: FormEvent) {
    e.preventDefault();
    const q = question.trim();
    if (!q) return;
    setError(null);
    setLoading(true);

    const userItem: ChatItem = { id: `${Date.now()}-u`, from: "user", text: q };
    setItems((prev) => [...prev, userItem]);
    setQuestion("");

    try {
      const res = await http.post("/api/ai/ask", { question: q });
      const answer = res.data?.answer || "No answer available.";
      const assistantItem: ChatItem = { id: `${Date.now()}-a`, from: "assistant", text: answer };
      setItems((prev) => [...prev, assistantItem]);
    } catch (err: any) {
      setError(err?.response?.data?.message || "AI request failed");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="page-inner-narrow">
      <h1 className="page-heading">AI Assistant</h1>
      <p className="page-subheading">Ask anything about courier operations, tracking, or payments.</p>

      {error && <div className="alert-error">{error}</div>}

      <div className="dark-card" style={{ padding: 0, overflow: "hidden" }}>
        {/* Chat window */}
        <div className="chat-window">
          {items.map((it) => (
            <div
              key={it.id}
              className={`chat-bubble ${it.from === "user" ? "chat-bubble-user" : "chat-bubble-assistant"}`}
            >
              {it.text}
            </div>
          ))}

          {loading && (
            <div className="chat-bubble chat-bubble-assistant">
              <div className="loading-row">
                <div className="loading-dot" />
                <div className="loading-dot" />
                <div className="loading-dot" />
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        {/* Input bar */}
        <div style={{ padding: "16px", borderTop: "1px solid var(--border)" }}>
          <form onSubmit={onAsk} className="chat-input-row">
            <input
              className="chat-input"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              placeholder="e.g. How do I track my parcel?"
              disabled={loading}
            />
            <button
              type="submit"
              disabled={loading || !question.trim()}
              className="btn-primary"
              style={{ whiteSpace: "nowrap" }}
            >
              {loading ? "ΓÇª" : "Send Γåæ"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

import { useState } from "react";
import type { FormEvent } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import type { AppDispatch, RootState } from "../store/store";
import { createParcel } from "../features/parcels/parcelSlice";

export default function CreateParcelPage() {
  const dispatch = useDispatch<AppDispatch>();
  const navigate = useNavigate();
  const auth = useSelector((s: RootState) => s.auth);
  const parcels = useSelector((s: RootState) => s.parcels);

  const [pickupScheduledAt, setPickupScheduledAt] = useState("");
  const [pickupAddressLine1, setPickupAddressLine1] = useState("");
  const [pickupAddressLine2, setPickupAddressLine2] = useState("");
  const [pickupCity, setPickupCity] = useState("");
  const [receiverName, setReceiverName] = useState("");
  const [receiverPhone, setReceiverPhone] = useState("");
  const [receiverAddressLine1, setReceiverAddressLine1] = useState("");
  const [receiverAddressLine2, setReceiverAddressLine2] = useState("");
  const [receiverCity, setReceiverCity] = useState("");
  const [parcelType, setParcelType] = useState("");
  const [weightKg, setWeightKg] = useState("");
  const [notes, setNotes] = useState("");
  const [formError, setFormError] = useState<string | null>(null);

  async function onSubmit(e: FormEvent) {
    e.preventDefault();
    setFormError(null);
    try {
      await dispatch(
        createParcel({
          pickupScheduledAt: pickupScheduledAt || null,
          pickupAddressLine1,
          pickupAddressLine2: pickupAddressLine2 || null,
          pickupCity: pickupCity || null,
          receiverName,
          receiverPhone,
          receiverAddressLine1,
          receiverAddressLine2: receiverAddressLine2 || null,
          receiverCity: receiverCity || null,
          parcelType: parcelType || null,
          weightKg: weightKg ? Number(weightKg) : null,
          notes: notes || null,
        })
      ).unwrap();
      navigate("/history");
    } catch (err: any) {
      setFormError(err?.message || parcels.createError || "Failed to create parcel");
    }
  }

